import{_ as i,o as a,c as o,ak as n}from"./chunks/framework.BxL5Xhi-.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/AI核心概念.md","filePath":"ai/AI核心概念.md"}'),t={name:"ai/AI核心概念.md"};function e(r,l,s,g,p,c){return a(),o("div",null,[...l[0]||(l[0]=[n('<h2 id="_1-llm-large-language-model" tabindex="-1">1. LLM（Large Language Model） <a class="header-anchor" href="#_1-llm-large-language-model" aria-label="Permalink to “1. LLM（Large Language Model）”">​</a></h2><p><strong>大语言模型</strong>，当前 AI 的核心底座。</p><ul><li>本质：<strong>超大规模神经网络</strong></li><li>能力：理解语言、生成文本、写代码、推理、总结、对话</li><li>代表：GPT-4、Claude、Llama、文心一言、通义千问、字节豆包</li></ul><h2 id="_2-token" tabindex="-1">2. Token <a class="header-anchor" href="#_2-token" aria-label="Permalink to “2. Token”">​</a></h2><p>LLM <strong>读写文字的最小单位</strong>，像 “文字原子”。</p><ul><li><p>中文：<strong>1 个 Token ≈ 1~2 个汉字</strong></p></li><li><p>英文：<strong>1 个 Token ≈ 3~4 个字母</strong></p></li><li><p>作用：</p><ul><li>模型<strong>按 Token 计费 / 限长度</strong></li><li>决定<strong>上下文能装多少内容</strong></li><li>影响生成速度</li></ul></li></ul><h2 id="_3-context-上下文-上下文窗口" tabindex="-1">3. Context（上下文 / 上下文窗口） <a class="header-anchor" href="#_3-context-上下文-上下文窗口" aria-label="Permalink to “3. Context（上下文 / 上下文窗口）”">​</a></h2><p>模型<strong>当前 “记得” 的所有内容</strong>，包括：</p><ul><li>历史对话</li><li>你上传的文档</li><li>系统提示</li><li>模型刚生成的内容</li></ul><p><strong>Context Window = 最大能记住的 Token 数量</strong></p><p>比如 8K、16K、32K、128K 都是指 Token 上限。</p><h2 id="_4-prompt-提示词" tabindex="-1">4. Prompt（提示词） <a class="header-anchor" href="#_4-prompt-提示词" aria-label="Permalink to “4. Prompt（提示词）”">​</a></h2><p><strong>你发给模型的指令</strong>，决定模型怎么回答。</p><ul><li><p>系统 Prompt：设定角色、规则、风格</p></li><li><p>用户 Prompt：具体问题 / 任务</p><p>好 Prompt = 清晰角色 + 明确任务 + 格式要求 + 示例</p></li></ul><h2 id="_5-tool-工具" tabindex="-1">5. Tool（工具） <a class="header-anchor" href="#_5-tool-工具" aria-label="Permalink to “5. Tool（工具）”">​</a></h2><p>LLM 本身<strong>不会联网、不会计算、不会操作软件</strong>，</p><p>通过<strong>调用外部工具</strong>扩展能力：</p><ul><li>计算器</li><li>搜索引擎（联网）</li><li>代码解释器</li><li>文件读写</li><li>API 调用</li><li>数据库查询</li></ul><h2 id="_6-mcp-tool-calling-function-calling-标准" tabindex="-1">6. MCP（Tool Calling / Function Calling 标准） <a class="header-anchor" href="#_6-mcp-tool-calling-function-calling-标准" aria-label="Permalink to “6. MCP（Tool Calling / Function Calling 标准）”">​</a></h2><p>MCP 是<strong>工具调用的标准化协议</strong>（类似通用 “插座规范”），</p><p>让模型能<strong>统一、稳定、结构化</strong>调用各种工具：</p><ul><li>决定什么时候调用工具</li><li>传什么参数</li><li>解析返回结果</li><li>决定下一步做什么</li></ul><blockquote><p>现在主流 AI 框架都在向 <strong>MCP 标准化</strong>靠拢，让跨模型、跨工具更通用。</p></blockquote><h2 id="_7-agent-智能体" tabindex="-1">7. Agent（智能体） <a class="header-anchor" href="#_7-agent-智能体" aria-label="Permalink to “7. Agent（智能体）”">​</a></h2><p><strong>能自主思考、规划、执行、反思的 AI</strong>，不是简单问答。</p><p>一个 Agent = LLM 大脑 + Context 记忆 + Tool 能力 + 规划逻辑</p><p>它会：</p><ol><li>理解你的目标</li><li><strong>拆解步骤</strong></li><li>选择工具 / 行动</li><li>执行并观察结果</li><li>修正、迭代直到完成任务</li></ol><h2 id="_8-agent-skill-智能体技能" tabindex="-1">8. Agent Skill（智能体技能） <a class="header-anchor" href="#_8-agent-skill-智能体技能" aria-label="Permalink to “8. Agent Skill（智能体技能）”">​</a></h2><p>Agent 可复用的<strong>专业能力模块</strong>，类似 “技能包”。</p><p>例如：</p><ul><li>搜索总结 Skill</li><li>写代码 Skill</li><li>数据分析 Skill</li><li>邮件自动处理 Skill</li><li>表格处理 Skill</li><li>多步骤任务规划 Skill</li></ul><p>Skill 让 Agent<strong>更专业、更稳定、可组合</strong>。</p>',33)])])}const _=i(t,[["render",e]]);export{d as __pageData,_ as default};
